using System;class A{static int n,lx,rx,ly;static int[]sx=new int[30],sy=new int[30];static double tx;static double Gy(double px){for(int i=0;i<n-1;i++)if(px>=sx[i]&&(px<sx[i+1]||i==n-2))return sy[i]+(double)(sy[i+1]-sy[i])*(px-sx[i])/(sx[i+1]-sx[i]);return sy[n-1];}static void Main(){n=int.Parse(Console.ReadLine());for(int i=0;i<n;i++){var p=Console.ReadLine().Split();sx[i]=int.Parse(p[0]);sy[i]=int.Parse(p[1]);}for(int i=0;i<n-1;i++)if(sy[i]==sy[i+1]&&sx[i+1]-sx[i]>=1000){lx=sx[i];rx=sx[i+1];ly=sy[i];break;}tx=(lx+rx)/2.0;for(;;){var p=Console.ReadLine().Split();int X=int.Parse(p[0]),Y=int.Parse(p[1]),hs=int.Parse(p[2]),vs=int.Parse(p[3]),fu=int.Parse(p[4]),ro=int.Parse(p[5]),pw=int.Parse(p[6]);double dg=Y-Gy(X),df=Y-ly;bool over=X>=lx&&X<=rx;int ah=Math.Abs(hs),blocked=0;if(!over){int step=X<lx?50:-50;double cx=X;for(int j=0;j<200;j++){cx+=step;if(cx<0||cx>6999)break;if((step>0&&cx>rx)||(step<0&&cx<lx))break;if(Gy(cx)>Y-100){blocked=1;break;}}}int tr=0,tp=4;if(dg<100&&vs<-30){tr=0;tp=4;}else if(blocked==1&&!over){tp=vs<10?4:3;tr=X<lx?-20:20;}else if(!over){if(X<lx){if(hs<0)tr=30;else if(hs>80)tr=60;else if(hs>40)tr=30;else tr=-30-Math.Min(30,Math.Max(0,(lx-X)/50));}else{if(hs>0)tr=-30;else if(hs<-80)tr=-60;else if(hs<-40)tr=-30;else tr=30+Math.Min(30,Math.Max(0,(X-rx)/50));}tp=4;}else if(df<400&&ah<=25){tr=0;tp=vs<-38?4:vs<-25?3:vs<-10?2:vs>5?0:1;}else if(over){tr=ah>20?(hs>0?Math.Min(45,hs):Math.Max(-45,hs)):(X<tx-100?-10:X>tx+100?10:0);tp=vs<-35?4:tr!=0?4:vs>-15?2:3;}else{tr=ah>5?(hs>0?15:-15):0;tp=vs<-30?4:3;}int dr=Math.Max(-90,Math.Min(90,tr));dr=Math.Max(ro-15,Math.Min(ro+15,dr));int dp=Math.Max(0,Math.Min(4,tp));dp=Math.Max(pw-1,Math.Min(pw+1,dp));Console.WriteLine($"{dr} {dp}");Console.Out.Flush();}}}
